import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(origin, destination):
        distance = np.linalg.norm(origin - destination)
        return distance / truck_speed

    def time_window_penalty(arrival_time, time_window):
        start, end = time_window
        if arrival_time < start:
            return start - arrival_time  # early arrival, must wait
        elif arrival_time > end:
            return (arrival_time - end) * 10  # late arrival, large penalty
        else:
            return 0  # on time

    best_node = None
    min_penalty = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        estimated_arrival_time = current_time + travel_time
        penalty = time_window_penalty(estimated_arrival_time, time_windows[i])

        # Consider time windows and synchronization
        if penalty < min_penalty:
            min_penalty = penalty
            best_node = i

    return best_node
